// Parse Lead Data: Normalize and extract lead fields from webhook payload

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const body = item.json.body || item.json;

    // Extract and normalize lead fields
    const lead = {
      first_name: (body.first_name || body.firstName || '').trim(),
      last_name: (body.last_name || body.lastName || '').trim(),
      email: (body.email || '').trim().toLowerCase(),
      phone: (body.phone || '').trim(),
      company: (body.company || 'Individual').trim(),
      portfolio_size: parseInt(body.portfolio_size || body.portfolioSize || 0, 10),
      monthly_budget: parseInt(body.monthly_budget || body.monthlyBudget || 0, 10),
      primary_need: (body.primary_need || body.primaryNeed || '').trim(),
      timeline: (body.timeline || '').trim(),
      current_pain: (body.current_pain || body.currentPain || '').trim(),
      property_type: (body.property_type || body.propertyType || '').trim(),
      location: (body.location || '').trim(),
      heard_about_us: (body.heard_about_us || body.heardAboutUs || '').trim(),
      received_at: new Date().toISOString()
    };

    // Validate required fields
    if (!lead.email) {
      throw new Error('Email is required');
    }
    if (!lead.first_name) {
      throw new Error('First name is required');
    }

    results.push({ json: lead });
  } catch (error) {
    results.push({ 
      json: { 
        error: true, 
        message: error.message,
        raw_input: item.json 
      } 
    });
  }
}

return results;

// Build Scoring Prompt: Format lead data as structured context for Claude

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const lead = item.json;

    // Build the lead context string
    const leadContext = `
LEAD INFORMATION:
- Name: ${lead.first_name} ${lead.last_name}
- Email: ${lead.email}
- Phone: ${lead.phone}
- Company: ${lead.company}
- Portfolio Size: ${lead.portfolio_size} units
- Monthly Budget: $${lead.monthly_budget}
- Primary Need: ${lead.primary_need}
- Timeline: ${lead.timeline}
- Current Pain Point: ${lead.current_pain}
- Property Type: ${lead.property_type}
- Location: ${lead.location}
- How They Found Us: ${lead.heard_about_us}
`;

    const userPrompt = leadContext + `
Score this lead 1-10 based on these criteria:
- Budget fit (target $2,000+/mo): 0-3 points
- Portfolio size (target 10+ units): 0-2 points
- Urgency/timeline (immediate need = higher score): 0-2 points
- Service-need match (AI automation, tenant screening, lease ops = high fit): 0-2 points
- Decision-maker signals (company name, specific pain points articulated): 0-1 point

Tier rules: score 8-10 = hot, 5-7 = warm, 1-4 = cold

Return this exact JSON structure:
{
  "score": 0,
  "tier": "hot|warm|cold",
  "reasoning": "2-3 sentence summary of why this score",
  "key_signals": ["signal 1", "signal 2", "signal 3"],
  "recommended_action": "specific next step for the sales team",
  "budget_fit": "strong|moderate|weak",
  "urgency": "high|medium|low",
  "personalization_hook": "one specific thing to reference in outreach that will resonate with this prospect"
}`;

    const messages = [
      {
        role: "system",
        content: "You are a lead qualification AI for an AI implementation consulting agency specializing in property management automation. Analyze inbound leads and score their fit. Return ONLY valid JSON — no markdown, no code blocks."
      },
      {
        role: "user",
        content: userPrompt
      }
    ];

    results.push({ 
      json: {
        ...lead,
        messages: messages,
        prompt_built_at: new Date().toISOString()
      } 
    });
  } catch (error) {
    results.push({ 
      json: { 
        ...item.json,
        error: true, 
        message: 'Failed to build prompt: ' + error.message 
      } 
    });
  }
}

return results;

// Parse AI Score: Extract score, tier, reasoning from Claude response

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Get lead data from upstream Build Scoring Prompt node
    const leadData = $('Build Scoring Prompt').item.json;

    // Get Claude's response
    const claudeResponse = item.json;
    let content = '';

    // Handle OpenRouter response format
    if (claudeResponse.choices && claudeResponse.choices.length > 0) {
      content = claudeResponse.choices[0].message?.content || '';
    } else if (claudeResponse.content) {
      content = claudeResponse.content;
    }

    // Clean the content - remove markdown code blocks if present
    content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    // Parse the JSON response
    let scoreData;
    try {
      scoreData = JSON.parse(content);
    } catch (parseError) {
      // Try to extract JSON from the response
      const jsonMatch = content.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        scoreData = JSON.parse(jsonMatch[0]);
      } else {
        throw new Error('Could not parse AI response as JSON');
      }
    }

    // Validate required fields
    const score = parseInt(scoreData.score, 10);
    if (isNaN(score) || score < 1 || score > 10) {
      throw new Error('Invalid score value: ' + scoreData.score);
    }

    const tier = (scoreData.tier || '').toLowerCase();
    if (!['hot', 'warm', 'cold'].includes(tier)) {
      throw new Error('Invalid tier value: ' + scoreData.tier);
    }

    // Build the result with lead data + AI analysis
    results.push({
      json: {
        // Lead data
        first_name: leadData.first_name,
        last_name: leadData.last_name,
        email: leadData.email,
        phone: leadData.phone,
        company: leadData.company,
        portfolio_size: leadData.portfolio_size,
        monthly_budget: leadData.monthly_budget,
        primary_need: leadData.primary_need,
        timeline: leadData.timeline,
        current_pain: leadData.current_pain,
        property_type: leadData.property_type,
        location: leadData.location,
        heard_about_us: leadData.heard_about_us,
        received_at: leadData.received_at,

        // AI analysis
        score: score,
        tier: tier,
        reasoning: scoreData.reasoning || '',
        key_signals: scoreData.key_signals || [],
        recommended_action: scoreData.recommended_action || '',
        budget_fit: scoreData.budget_fit || 'unknown',
        urgency: scoreData.urgency || 'unknown',
        personalization_hook: scoreData.personalization_hook || '',

        // Metadata
        scored_at: new Date().toISOString(),
        model_used: 'claude-3.5-sonnet',
        raw_ai_response: content
      }
    });
  } catch (error) {
    // On error, still pass through lead data with error flag
    const leadData = $('Build Scoring Prompt').item.json || {};
    results.push({
      json: {
        ...leadData,
        score: 5,
        tier: 'warm',
        reasoning: 'AI scoring failed - defaulting to warm lead for manual review',
        key_signals: ['AI scoring error'],
        recommended_action: 'Manual review required',
        budget_fit: 'unknown',
        urgency: 'unknown',
        personalization_hook: '',
        error: true,
        error_message: error.message,
        scored_at: new Date().toISOString()
      }
    });
  }
}

return results;

// Final Summary: Return execution summary for hot leads

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Get data from Parse AI Score (canonical source)
    const leadData = $('Parse AI Score').item.json;

    const summary = {
      status: 'success',
      lead_name: leadData.first_name + ' ' + leadData.last_name,
      email: leadData.email,
      company: leadData.company,
      score: leadData.score,
      tier: leadData.tier,
      actions_taken: [
        'HubSpot contact created',
        'Personalized hot lead email sent',
        'Slack alert posted',
        'Lead logged to Google Sheets'
      ],
      key_signals: leadData.key_signals,
      recommended_next_step: leadData.recommended_action,
      processed_at: new Date().toISOString()
    };

    results.push({ json: summary });
  } catch (error) {
    results.push({
      json: {
        status: 'error',
        error_message: error.message,
        processed_at: new Date().toISOString()
      }
    });
  }
}

return results;

// Log Error Details: Format error information for alerting

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const errorData = item.json;

    const errorLog = {
      error_type: 'Workflow Execution Error',
      workflow_name: 'AI Lead Qualification & CRM Entry',
      timestamp: new Date().toISOString(),
      error_message: errorData.execution?.error?.message || errorData.message || 'Unknown error',
      error_node: errorData.execution?.error?.node?.name || 'Unknown node',
      execution_id: errorData.execution?.id || 'Unknown',
      stack_trace: errorData.execution?.error?.stack || '',
      raw_error: JSON.stringify(errorData, null, 2).substring(0, 1000)
    };

    results.push({ json: errorLog });
  } catch (error) {
    results.push({
      json: {
        error_type: 'Error Processing Failed',
        error_message: error.message,
        timestamp: new Date().toISOString()
      }
    });
  }
}

return results;
